Sequential Effect composition is cleanest via `Effect.gen` with `yield*`. Declare tagged errors for each failure mode so the returned Effect exposes the union in its E channel.

```typescript
import { Effect, Data } from "effect";

class UserNotFound extends Data.TaggedError("UserNotFound")<{ readonly id: string }> {}
class PostsUnavailable extends Data.TaggedError("PostsUnavailable")<{ readonly userId: string }> {}

interface User { readonly id: string; readonly name: string }
interface Post { readonly id: string; readonly title: string }

declare const fetchUser: (id: string) => Effect.Effect<User, UserNotFound>;
declare const fetchPosts: (userId: string) => Effect.Effect<ReadonlyArray<Post>, PostsUnavailable>;

const program = (id: string): Effect.Effect<{ user: User; posts: ReadonlyArray<Post> }, UserNotFound | PostsUnavailable> =>
  Effect.gen(function* () {
    const user = yield* fetchUser(id);
    const posts = yield* fetchPosts(user.id);
    return { user, posts } as const;
  });

export { program };
```

Layers declare how services are constructed. `Layer.succeed` is for plain values, `Layer.effect` runs an Effect to build the service, and `Layer.provide` wires inner layer dependencies before `Effect.provide` closes the R channel.

```typescript
import { Effect, Layer, Context } from "effect";

interface Config { readonly level: "info" | "debug" }
const Config = Context.GenericTag<Config>("app/Config");

interface Logger { readonly log: (msg: string) => Effect.Effect<void> }
const Logger = Context.GenericTag<Logger>("app/Logger");

const ConfigLive = Layer.succeed(Config, { level: "info" });

const LoggerLive = Layer.effect(
  Logger,
  Effect.gen(function* () {
    const cfg = yield* Config;
    return { log: (msg) => Effect.sync(() => console.log(`[${cfg.level}] ${msg}`)) };
  })
);

// Logger depends on Config; provide Config into LoggerLive, then merge.
const MainLive = Layer.merge(ConfigLive, Layer.provide(LoggerLive, ConfigLive));

const program = Effect.gen(function* () {
  const logger = yield* Logger;
  yield* logger.log("starting");
});

export const runnable = Effect.provide(program, MainLive);
```

```typescript
