`Data.TaggedError` gives you a class with a `_tag` discriminator. `Effect.catchTag` narrows on the tag and removes that variant from the E channel while keeping the rest.

```typescript
import { Effect, Data } from "effect";

class NetworkError extends Data.TaggedError("NetworkError")<{ readonly url: string }> {}
class ParseError extends Data.TaggedError("ParseError")<{ readonly reason: string }> {}

declare const fetchJson: (url: string) => Effect.Effect<unknown, NetworkError | ParseError>;

const program = (url: string): Effect.Effect<unknown, ParseError> =>
  fetchJson(url).pipe(
    Effect.catchTag("NetworkError", (e) =>
      Effect.succeed({ offline: true, url: e.url })
    )
  );

export { program };
```

Compose an exponential schedule with jitter, then intersect it with `Schedule.recurs(n)` so the retry count is bounded.

```typescript
import { Effect, Schedule, Duration, Data } from "effect";

class HttpError extends Data.TaggedError("HttpError")<{ readonly status: number }> {}

declare const call: Effect.Effect<string, HttpError>;

// Exponential 100ms base, with jitter, capped at 5 retries.
const policy = Schedule.exponential(Duration.millis(100)).pipe(
  Schedule.jittered,
  Schedule.intersect(Schedule.recurs(5))
);

export const resilient: Effect.Effect<string, HttpError> = Effect.retry(call, policy);
```

`Effect.all` defaults to sequential. Pass `{ concurrency: "unbounded" }` for full parallel, or a number for a bounded pool.

```typescript
import { Effect } from "effect";

const loadUser: Effect.Effect<{ name: string }> = Effect.succeed({ name: "Ada" });
const loadPrefs: Effect.Effect<{ theme: "dark" | "light" }> = Effect.succeed({ theme: "dark" });
const loadFlags: Effect.Effect<ReadonlyArray<string>> = Effect.succeed(["beta"]);

const sequential: Effect.Effect<
  readonly [{ name: string }, { theme: "dark" | "light" }, ReadonlyArray<string>]
> = Effect.all([loadUser, loadPrefs, loadFlags]);

const parallel: Effect.Effect<
  readonly [{ name: string }, { theme: "dark" | "light" }, ReadonlyArray<string>]
> = Effect.all([loadUser, loadPrefs, loadFlags], { concurrency: "unbounded" });

export { sequential, parallel };
```

