```typescript
import { Effect, Context, Layer, Data } from "effect";

class EmptyInput extends Data.TaggedError("EmptyInput")<{}> {}
class DbError extends Data.TaggedError("DbError")<{ readonly cause: string }> {}

interface Db { readonly save: (s: string) => Effect.Effect<string, DbError> }
const Db = Context.GenericTag<Db>("app/Db");

interface Log { readonly info: (m: string) => Effect.Effect<void> }
const Log = Context.GenericTag<Log>("app/Log");

const validate = (s: string): Effect.Effect<string, EmptyInput> =>
  s.trim().length === 0 ? Effect.fail(new EmptyInput()) : Effect.succeed(s.trim());

const program = (raw: string): Effect.Effect<string, EmptyInput | DbError, Db | Log> =>
  Effect.gen(function* () {
    const clean = yield* validate(raw);
    const db = yield* Db;
    const log = yield* Log;
    const id = yield* db.save(clean);
    yield* log.info(`saved ${id}`);
    return id;
  });

const DbLive = Layer.succeed(Db, { save: (s) => Effect.succeed(`id-${s.length}`) });
const LogLive = Layer.succeed(Log, { info: (m) => Effect.sync(() => console.log(m)) });
const Main = Layer.merge(DbLive, LogLive);

export const runnable = (s: string) => Effect.provide(program(s), Main);
```

Define an interface, declare a `Context.GenericTag`, then `yield*` the tag inside `Effect.gen` to resolve the implementation.

```typescript
import { Effect, Context, Layer, Option } from "effect";

interface Cache {
  readonly get: (k: string) => Effect.Effect<Option.Option<string>>;
  readonly set: (k: string, v: string) => Effect.Effect<void>;
}

const Cache = Context.GenericTag<Cache>("app/Cache");

const program = (key: string, value: string): Effect.Effect<string, never, Cache> =>
  Effect.gen(function* () {
    const cache = yield* Cache;
    yield* cache.set(key, value);
    const got = yield* cache.get(key);
    return Option.getOrElse(got, () => "miss");
  });

const memo = new Map<string, string>();
const CacheLive = Layer.succeed(Cache, {
  get: (k) => Effect.sync(() => Option.fromNullable(memo.get(k))),
  set: (k, v) => Effect.sync(() => { memo.set(k, v); }),
});

export const runnable = Effect.provide(program("k", "v"), CacheLive);
```

Add a catchTag handler for a RateLimit error to this Effect program, leaving Timeout untouched in the error channel:

```ts
import { Effect, Data } from "effect";
class RateLimit extends Data.TaggedError("RateLimit")<{ retryAfter: number }> {}
class Timeout extends Data.TaggedError("Timeout")<{}> {}
declare const call: Effect.Effect<string, RateLimit | Timeout>;
```

`Effect.catchTag("RateLimit", handler)` removes RateLimit from the E channel. The handler must not re-introduce that tag, so we return a plain success here to keep the final error type as `Timeout`.

```typescript
import { Effect, Data } from "effect";

class RateLimit extends Data.TaggedError("RateLimit")<{ readonly retryAfter: number }> {}
class Timeout extends Data.TaggedError("Timeout")<{}> {}

declare const call: Effect.Effect<string, RateLimit | Timeout>;

const handled: Effect.Effect<string, Timeout> = call.pipe(
  Effect.catchTag("RateLimit", (e) =>
    Effect.succeed(`rate-limited; retry in ${e.retryAfter}ms`)
  )
);

export { handled };
```

