```typescript
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

interface ParseError { readonly _tag: "ParseError"; readonly input: string }
interface RangeError { readonly _tag: "RangeError"; readonly value: number }

const parseInt10 = (s: string): E.Either<ParseError, number> => {
  const n = Number.parseInt(s, 10);
  return Number.isNaN(n) ? E.left({ _tag: "ParseError", input: s }) : E.right(n);
};

const positive = (n: number): E.Either<RangeError, number> =>
  n > 0 ? E.right(n) : E.left({ _tag: "RangeError", value: n });

const pipeline = (input: string): string =>
  pipe(
    parseInt10(input),
    E.chainW(positive),
    E.map((n) => `${n} units`),
    E.mapLeft((err) => `invalid: ${err._tag}`),
    E.match(
      (e) => e,
      (ok) => ok
    )
  );

export { pipeline };
```

