Inside an `Effect.gen` body, each `yield*` unwraps an `Effect<A, E, R>` to `A` while TypeScript collects every yielded `E` into the union on the returned generator. That union becomes the E channel of the Effect returned by `Effect.gen`, so no type information is lost across sequential steps.

```typescript
import { Effect, Data } from "effect";

class NotFound extends Data.TaggedError("NotFound")<{ readonly id: string }> {}
class Forbidden extends Data.TaggedError("Forbidden")<{ readonly id: string }> {}

declare const load: (id: string) => Effect.Effect<{ ownerId: string }, NotFound>;
declare const checkAccess: (ownerId: string) => Effect.Effect<void, Forbidden>;

const program = (
  id: string,
): Effect.Effect<{ ownerId: string }, NotFound | Forbidden> =>
  Effect.gen(function* () {
    const doc = yield* load(id);
    yield* checkAccess(doc.ownerId);
    return doc;
  });

export { program };
```

