Compose `Schedule.exponential` with `Schedule.recurs` via `Schedule.intersect` to bound the attempt count while keeping exponential growth.

```typescript
import { Effect, Schedule, Duration, Data } from "effect";

class TransientError extends Data.TaggedError("TransientError")<{}> {}

declare const flaky: Effect.Effect<number, TransientError>;

// Exponential growth from 50ms base, bounded to at most 6 retries.
const bounded = Schedule.exponential(Duration.millis(50)).pipe(
  Schedule.intersect(Schedule.recurs(6))
);

export const resilient: Effect.Effect<number, TransientError> = Effect.retry(
  flaky,
  bounded
);
```

