The deprecated helper was a v2 shape. In Effect v3 the tag itself is yieldable — `yield* Tag` resolves the service.

```typescript
import { Effect, Context, Layer } from "effect";

interface Db {
  readonly query: (sql: string) => Effect.Effect<ReadonlyArray<unknown>>;
}

const Db = Context.GenericTag<Db>("app/Db");

const program: Effect.Effect<ReadonlyArray<unknown>, never, Db> = Effect.gen(
  function* () {
    const db = yield* Db; // v3: yield the tag directly
    return yield* db.query("select 1");
  }
);

const DbLive = Layer.succeed(Db, { query: () => Effect.succeed([] as const) });

export const runnable = Effect.provide(program, DbLive);
```

