```typescript
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { sequenceT } from "fp-ts/Apply";

interface Form { readonly name: string; readonly age: number; readonly email: string }
interface User  { readonly name: string; readonly age: number; readonly email: string }

type Err = string;
type V<A> = E.Either<RNEA.ReadonlyNonEmptyArray<Err>, A>;

const lift = <A>(e: E.Either<Err, A>): V<A> =>
  pipe(e, E.mapLeft((msg) => [msg] as RNEA.ReadonlyNonEmptyArray<Err>));

const validateName = (s: string): V<string> =>
  lift(s.trim().length > 0 ? E.right(s) : E.left("name is empty"));

const validateAge = (n: number): V<number> =>
  lift(n >= 18 ? E.right(n) : E.left("age must be >= 18"));

const validateEmail = (s: string): V<string> =>
  lift(s.includes("@") ? E.right(s) : E.left("email invalid"));

const Applicative = E.getApplicativeValidation(RNEA.getSemigroup<Err>());

const validate = (f: Form): V<User> =>
  pipe(
    sequenceT(Applicative)(
      validateName(f.name),
      validateAge(f.age),
      validateEmail(f.email)
    ),
    E.map(([name, age, email]) => ({ name, age, email }))
  );

export { validate };
```

Capability add-on: add Effect.tap logging to this program so each step prints without changing the value.

```ts
import { Effect } from "effect";
declare const step1: Effect.Effect<number>;
declare const step2: (n: number) => Effect.Effect<string>;
```

`Effect.tap` runs a side effect and discards its result, preserving the outer value.

```typescript
import { Effect, Console } from "effect";

declare const step1: Effect.Effect<number>;
declare const step2: (n: number) => Effect.Effect<string>;

// tap != flatMap: tap's returned effect is run for side effects only.
const program: Effect.Effect<string> = Effect.gen(function* () {
  const n = yield* step1.pipe(Effect.tap((v) => Console.log(`step1=${v}`)));
  const s = yield* step2(n).pipe(Effect.tap((v) => Console.log(`step2=${v}`)));
  return s;
});

export { program };
```

