Use `O.chain` for steps that return `Option<B>`; it flattens `Option<Option<B>>` to `Option<B>`. Reserve `O.map` for pure transforms.

```typescript
import { pipe } from "fp-ts/function";
import * as O from "fp-ts/Option";

interface Profile { readonly name?: string | null; readonly dob?: string | null }
interface User { readonly profile?: Profile | null }

const parseYear = (dob: string): O.Option<number> => {
  const y = Number.parseInt(dob.slice(0, 4), 10);
  return Number.isNaN(y) ? O.none : O.some(y);
};

const birthYearOrZero = (user: User): number =>
  pipe(
    user.profile,
    O.fromNullable,
    O.chain((p) => O.fromNullable(p.dob)),
    O.chain(parseYear),
    O.getOrElse(() => 0)
  );

export { birthYearOrZero };
```

