```typescript
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

interface JsonError { readonly _tag: "JsonError"; readonly msg: string }
interface FieldError { readonly _tag: "FieldError"; readonly field: string }

const parseJson = (s: string): E.Either<JsonError, unknown> => {
  try {
    return E.right(JSON.parse(s) as unknown);
  } catch (e) {
    return E.left({ _tag: "JsonError", msg: e instanceof Error ? e.message : "bad" });
  }
};

const getStringField = (field: string) => (j: unknown): E.Either<FieldError, string> => {
  if (typeof j === "object" && j !== null && field in j) {
    const v = (j as Record<string, unknown>)[field];
    if (typeof v === "string") return E.right(v);
  }
  return E.left({ _tag: "FieldError", field });
};

const getName = (raw: string): string =>
  pipe(
