`Effect.catchTag(tag, handler)` discriminates on the `_tag` field at the type level. The returned Effect has its E channel narrowed by the set difference of the matched tag, so handling two tags removes both from the remaining union.

```typescript
import { Effect, Data } from "effect";

class A extends Data.TaggedError("A")<{}> {}
class B extends Data.TaggedError("B")<{ readonly n: number }> {}
class C extends Data.TaggedError("C")<{}> {}

declare const op: Effect.Effect<string, A | B | C>;

// After catchTag("A") and catchTag("B") only C remains in the E channel.
const handled: Effect.Effect<string, C> = op.pipe(
  Effect.catchTag("A", () => Effect.succeed("default-A")),
  Effect.catchTag("B", (e) => Effect.succeed(`b=${e.n}`))
);

export { handled };
```

