import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";
import * as TE from "fp-ts/TaskEither";

type AppError =
  | { readonly _tag: "ParseError"; readonly input: string }
  | { readonly _tag: "NetError"; readonly cause: string };

const parse = (s: string): E.Either<AppError, number> => {
  const n = Number.parseInt(s, 10);
  return Number.isNaN(n)
    ? E.left({ _tag: "ParseError", input: s })
    : E.right(n);
};

const fetchDouble = (n: number): TE.TaskEither<AppError, number> =>
  TE.tryCatch(
    async () => n * 2,
    (u) => ({ _tag: "NetError", cause: u instanceof Error ? u.message : String(u) })
  );

const program = (raw: string): TE.TaskEither<AppError, number> =>
  pipe(
    TE.fromEither(parse(raw)),
    TE.chainW(fetchDouble)
  );

export { program };
